import { useMemo, useState } from "react";

const BANNER = "data:image/jpeg;base64,";

const TOKENS = ["wBTC","wETH","CELO","XAUoT"];
const INPUT_TOKENS = ["USDC","USDT"];
const WEEKDAYS = ["Monday","Tuesday","Wednesday","Thursday","Friday","Saturday","Sunday"];
const ICONS = { wBTC:"₿", wETH:"Ξ", CELO:"C", XAUoT:"🥇" };
const TOTAL = 100;
const MIN_TRANCHE = 0.5;
const MAX_DUR = 365;

function parseNum(v){const t=v.trim();if(!/^\d+(\.\d+)?$/.test(t))return null;const n=Number(t);return Number.isFinite(n)?n:null;}
function parseInt2(v){const t=v.trim();if(!/^\d+$/.test(t))return null;const n=Number(t);return Number.isSafeInteger(n)&&n>0?n:null;}
function amtErr(a){const n=parseNum(a);if(n===null)return"Ungültiger Betrag.";if(n<=0)return"Betrag muss > 0 sein.";return null;}
function durErr(d,a,tok){const dur=parseInt2(d),tot=parseNum(a);if(dur===null)return"Ganze positive Zahl erforderlich.";if(dur>MAX_DUR)return`Max ${MAX_DUR}.`;if(tot===null)return"Zuerst Betrag eingeben.";if(tot/dur<MIN_TRANCHE)return`Tranche muss ≥ ${MIN_TRANCHE} ${tok} sein.`;return null;}
function utcOf(t){const[h,m]=t.split(":").map(Number);if(!Number.isInteger(h)||!Number.isInteger(m))return"--:--";const d=new Date();d.setHours(h,m,0,0);return d.toISOString().slice(11,16);}

const C = {
  page:{background:"#0a1628",minHeight:"100vh",padding:16,fontFamily:"Inter,system-ui,sans-serif"},
  card:{maxWidth:420,margin:"0 auto",background:"rgba(255,255,255,0.06)",backdropFilter:"blur(12px)",border:"1px solid rgba(255,215,0,0.2)",borderRadius:12,padding:20,boxShadow:"0 8px 32px rgba(0,0,0,0.5)"},
  banner:{width:"100%",borderRadius:10,display:"block"},
  h1:{color:"#FFD700",fontSize:"2.2rem",fontWeight:900,margin:0,letterSpacing:"0.08em",textShadow:"0 0 20px rgba(255,215,0,0.4)"},
  h2:{color:"#e2e8f0",fontSize:"1.2rem",margin:0,fontWeight:700},
  eyebrow:{color:"#94a3b8",fontSize:"0.7rem",fontWeight:700,letterSpacing:"0.1em",textTransform:"uppercase",margin:"4px 0 0 0"},
  muted:{color:"#94a3b8",margin:0,fontSize:"0.9rem"},
  stack:{display:"flex",flexDirection:"column",gap:16},
  center:{textAlign:"center"},
  field:{display:"flex",flexDirection:"column",gap:6},
  label:{color:"#cbd5e1",fontSize:"0.85rem",fontWeight:600},
  input:{background:"rgba(255,255,255,0.08)",border:"1px solid rgba(255,215,0,0.3)",borderRadius:8,padding:"10px 12px",color:"#f1f5f9",font:"inherit",fontSize:"1rem",outline:"none",width:"100%",boxSizing:"border-box"},
  select:{background:"rgba(15,23,42,0.9)",border:"1px solid rgba(255,215,0,0.3)",borderRadius:8,padding:"10px 12px",color:"#f1f5f9",font:"inherit",fontSize:"1rem",width:"100%",boxSizing:"border-box"},
  row:{display:"flex",gap:10,justifyContent:"space-between"},
  amtRow:{display:"flex",gap:10,alignItems:"flex-start"},
  sliderRow:{display:"flex",flexDirection:"column",gap:4},
  labelRow:{display:"flex",justifyContent:"space-between",alignItems:"center"},
  err:{color:"#f87171",fontSize:"0.8rem",margin:0},
  hr:{border:0,borderTop:"1px solid rgba(255,215,0,0.2)",margin:"8px 0"},
  summary:{background:"rgba(255,215,0,0.06)",border:"1px solid rgba(255,215,0,0.2)",borderRadius:8,padding:12,color:"#e2e8f0",lineHeight:1.6,fontSize:"0.9rem"},
  infoBadge:{background:"rgba(255,215,0,0.1)",border:"1px solid rgba(255,215,0,0.3)",borderRadius:8,padding:12,color:"#fbbf24",fontSize:"0.85rem"},
  successCard:{background:"rgba(16,185,129,0.1)",border:"1px solid rgba(16,185,129,0.4)",borderRadius:10,padding:24,textAlign:"center",color:"#6ee7b7"},
};

function btn(variant){
  const base={minHeight:44,padding:"10px 20px",border:0,borderRadius:8,font:"inherit",fontWeight:700,cursor:"pointer",fontSize:"0.95rem",letterSpacing:"0.03em"};
  if(variant==="primary") return{...base,background:"linear-gradient(135deg,#FFD700,#FFA500)",color:"#0a1628"};
  if(variant==="secondary") return{...base,background:"rgba(255,215,0,0.15)",color:"#FFD700",border:"1px solid rgba(255,215,0,0.4)"};
  if(variant==="danger") return{...base,background:"rgba(239,68,68,0.2)",color:"#f87171",border:"1px solid rgba(239,68,68,0.4)"};
  if(variant==="success") return{...base,background:"linear-gradient(135deg,#10b981,#059669)",color:"#fff"};
  return base;
}

function init(){return{step:1,interval:null,totalAmount:"",inputToken:"USDC",percentages:{wBTC:0,wETH:0,CELO:0,XAUoT:0},duration:"",executionTime:"12:00",executionDay:"Monday",timezone:Intl.DateTimeFormat().resolvedOptions().timeZone||"UTC"};}

export default function App(){
  const[form,setForm]=useState(init);
  const[submitErr,setSubmitErr]=useState(null);
  const[submitting,setSubmitting]=useState(false);
  const[done,setDone]=useState(false);

  const upd=(k,v)=>{setSubmitErr(null);setForm(p=>({...p,[k]:v}));};
  const next=()=>setForm(p=>({...p,step:Math.min(p.step+1,6)}));
  const prev=()=>setForm(p=>({...p,step:Math.max(p.step-1,1)}));
  const reset=()=>{setSubmitErr(null);setSubmitting(false);setDone(false);setForm(init());};

  const allocated=useMemo(()=>TOKENS.reduce((s,t)=>s+form.percentages[t],0),[form.percentages]);
  const remaining=TOTAL-allocated;
  const ae=form.totalAmount?amtErr(form.totalAmount):null;
  const de=form.duration?durErr(form.duration,form.totalAmount,form.inputToken):null;
  const totalAmt=parseNum(form.totalAmount)??0;
  const dur=parseInt2(form.duration)??0;
  const tranche=dur>0?totalAmt/dur:0;
  const utc=utcOf(form.executionTime);

  const handleSlider=(tok,val)=>{
    const safe=Math.max(0,Math.min(100,val));
    const other=TOKENS.filter(t=>t!==tok).reduce((s,t)=>s+form.percentages[t],0);
    upd("percentages",{...form.percentages,[tok]:Math.min(safe,TOTAL-other)});
  };

  const submit=async()=>{
    if(!form.interval){setSubmitErr("Bitte Intervall wählen.");return;}
    if(amtErr(form.totalAmount)){setSubmitErr(amtErr(form.totalAmount));return;}
    if(allocated!==TOTAL){setSubmitErr("Allokation muss genau 100% ergeben.");return;}
    if(durErr(form.duration,form.totalAmount,form.inputToken)){setSubmitErr(durErr(form.duration,form.totalAmount,form.inputToken));return;}
    setSubmitting(true);setSubmitErr(null);
    await new Promise(r=>setTimeout(r,1000));
    setSubmitting(false);setDone(true);
  };

  if(done) return(
    <div style={C.page}><div style={C.card}>
      <div style={{...C.successCard,...C.stack}}>
        <div style={{fontSize:"3.5rem"}}>✅</div>
        <h2 style={{...C.h2,color:"#6ee7b7"}}>Plan eingereicht!</h2>
        <p style={{margin:0}}><strong style={{color:"#FFD700"}}>{form.totalAmount} {form.inputToken}</strong> über {form.duration} {form.interval==="daily"?"Tage":"Wochen"}</p>
        <p style={{margin:0,fontSize:"0.8rem",color:"#94a3b8"}}>⚡ In Produktion: Deploy auf Celo via MiniPay + DcaVault</p>
        <button style={btn("primary")} onClick={reset}>Neustart</button>
      </div>
    </div></div>
  );

  return(
    <div style={C.page}><div style={C.card}>

      {form.step===1&&(
        <div style={{...C.stack,...C.center}}>
          <img src={BANNER} alt="OSIRIS" style={C.banner}/>
          <h1 style={C.h1}>OSIRIS</h1>
          <p style={C.eyebrow}>OSnabrück Investment and Risk Management System</p>
          <p style={C.muted}>Wie oft soll der Plan investieren?</p>
          <div style={{display:"flex",flexDirection:"column",gap:10}}>
            <button style={btn("primary")} onClick={()=>{upd("interval","daily");next();}}>📅 Täglich</button>
            <button style={btn("secondary")} onClick={()=>{upd("interval","weekly");next();}}>🗓 Wöchentlich</button>
          </div>
        </div>
      )}

      {form.step===2&&(
        <div style={C.stack}>
          <h2 style={C.h2}>💰 Gesamtbetrag</h2>
          <div style={C.amtRow}>
            <div style={{...C.field,flex:1}}>
              <label style={C.label}>Betrag</label>
              <input style={C.input} type="text" value={form.totalAmount} onChange={e=>upd("totalAmount",e.target.value)} placeholder="100.00"/>
              {ae&&<p style={C.err}>{ae}</p>}
            </div>
            <div style={{...C.field,width:110,flexShrink:0}}>
              <label style={C.label}>Token</label>
              <select style={C.select} value={form.inputToken} onChange={e=>upd("inputToken",e.target.value)}>
                {INPUT_TOKENS.map(t=><option key={t} value={t}>{t}</option>)}
              </select>
            </div>
          </div>
          <div style={C.row}>
            <button style={btn("secondary")} onClick={prev}>← Zurück</button>
            <button style={{...btn("primary"),opacity:ae||!form.totalAmount?0.5:1}} disabled={!!ae||!form.totalAmount} onClick={next}>Weiter →</button>
          </div>
        </div>
      )}

      {form.step===3&&(
        <div style={C.stack}>
          <h2 style={C.h2}>📊 Token-Allokation</h2>
          {TOKENS.map(tok=>(
            <div key={tok} style={C.sliderRow}>
              <div style={C.labelRow}>
                <span style={{color:"#e2e8f0",fontSize:"0.9rem"}}>{ICONS[tok]} {tok}</span>
                <strong style={{color:"#FFD700"}}>{form.percentages[tok]}%</strong>
              </div>
              <input type="range" min="0" max="100" value={form.percentages[tok]}
                style={{width:"100%",accentColor:"#FFD700",height:4}}
                onChange={e=>handleSlider(tok,Number(e.target.value))}/>
            </div>
          ))}
          <div style={{...C.infoBadge,textAlign:"center",color:allocated===TOTAL?"#6ee7b7":"#fbbf24",background:allocated===TOTAL?"rgba(16,185,129,0.1)":"rgba(255,215,0,0.1)",borderColor:allocated===TOTAL?"rgba(16,185,129,0.4)":"rgba(255,215,0,0.3)"}}>
            {allocated===TOTAL?"✅ 100% allokiert":`${remaining}% verbleibend`}
          </div>
          <div style={C.row}>
            <button style={btn("secondary")} onClick={prev}>← Zurück</button>
            <button style={{...btn("primary"),opacity:allocated!==TOTAL?0.5:1}} disabled={allocated!==TOTAL} onClick={next}>Weiter →</button>
          </div>
        </div>
      )}

      {form.step===4&&(
        <div style={C.stack}>
          <h2 style={C.h2}>⏱ Laufzeit</h2>
          <div style={C.field}>
            <label style={C.label}>Anzahl {form.interval==="daily"?"Tage":"Wochen"}</label>
            <input style={C.input} type="text" value={form.duration} onChange={e=>upd("duration",e.target.value)} placeholder={form.interval==="daily"?"10":"4"}/>
            {de&&<p style={C.err}>{de}</p>}
          </div>
          {dur>0&&!de&&(
            <div style={{...C.infoBadge,textAlign:"center"}}>
              <div style={{fontSize:"0.75rem",textTransform:"uppercase",letterSpacing:"0.05em",marginBottom:4}}>Deine Tranche</div>
              <strong style={{fontSize:"1.1rem",color:"#FFD700"}}>{tranche.toFixed(2)} {form.inputToken} / {form.interval==="daily"?"Tag":"Woche"}</strong>
            </div>
          )}
          <div style={C.row}>
            <button style={btn("secondary")} onClick={prev}>← Zurück</button>
            <button style={{...btn("primary"),opacity:de||!form.duration?0.5:1}} disabled={!!de||!form.duration} onClick={next}>Weiter →</button>
          </div>
        </div>
      )}

      {form.step===5&&(
        <div style={C.stack}>
          <h2 style={C.h2}>📅 Zeitplan</h2>
          {form.interval==="weekly"&&(
            <div style={C.field}>
              <label style={C.label}>Wochentag</label>
              <select style={C.select} value={form.executionDay} onChange={e=>upd("executionDay",e.target.value)}>
                {WEEKDAYS.map(d=><option key={d} value={d}>{d}</option>)}
              </select>
            </div>
          )}
          <div style={C.field}>
            <label style={C.label}>Lokale Ausführungszeit</label>
            <input type="time" style={C.input} value={form.executionTime} onChange={e=>upd("executionTime",e.target.value)}/>
          </div>
          <div style={C.infoBadge}>
            ⏰ Ausführung {form.interval==="weekly"?`jeden ${form.executionDay}`:"täglich"} um {form.executionTime} Ortszeit<br/>
            <span style={{color:"#94a3b8",fontSize:"0.8rem"}}>= {utc} UTC · {form.timezone}</span>
          </div>
          <div style={C.row}>
            <button style={btn("secondary")} onClick={prev}>← Zurück</button>
            <button style={btn("primary")} onClick={next}>Weiter →</button>
          </div>
        </div>
      )}

      {form.step===6&&(
        <div style={{...C.stack,...C.center}}>
          <h2 style={C.h2}>📋 Zusammenfassung</h2>
          <div style={{...C.summary,textAlign:"left"}}>
            <p style={{margin:"4px 0"}}><span style={{color:"#94a3b8"}}>Betrag:</span> <strong style={{color:"#FFD700"}}>{form.totalAmount} {form.inputToken}</strong></p>
            <p style={{margin:"4px 0"}}><span style={{color:"#94a3b8"}}>Laufzeit:</span> <strong style={{color:"#e2e8f0"}}>{form.duration} {form.interval==="daily"?"Tage":"Wochen"}</strong></p>
            <p style={{margin:"4px 0"}}><span style={{color:"#94a3b8"}}>Tranche:</span> <strong style={{color:"#e2e8f0"}}>{tranche.toFixed(2)} {form.inputToken}</strong></p>
            <div style={C.hr}/>
            {TOKENS.filter(t=>form.percentages[t]>0).map(t=>(
              <p key={t} style={{margin:"4px 0"}}><strong style={{color:"#FFD700"}}>{form.percentages[t]}%</strong> <span style={{color:"#94a3b8"}}>→</span> {ICONS[t]} {t}</p>
            ))}
            <div style={C.hr}/>
            <p style={{margin:"4px 0"}}><span style={{color:"#94a3b8"}}>Zeitplan:</span> <strong style={{color:"#e2e8f0"}}>{form.interval==="weekly"?`jeden ${form.executionDay}`:"täglich"} · {form.executionTime}</strong></p>
            <p style={{margin:"4px 0"}}><span style={{color:"#94a3b8"}}>UTC:</span> <strong style={{color:"#e2e8f0"}}>{utc}</strong></p>
          </div>
          {submitErr&&<p style={C.err}>{submitErr}</p>}
          <div style={C.row}>
            <button style={btn("danger")} onClick={reset} disabled={submitting}>✗ Ablehnen</button>
            <button style={{...btn("success"),opacity:submitting?0.7:1}} onClick={submit} disabled={submitting}>
              {submitting?"⏳ Wird vorbereitet…":"✓ Bestätigen"}
            </button>
          </div>
        </div>
      )}

    </div></div>
  );
}
